const Q_GEOGRAPHY_2003=[{"id": "objective>Geography>2003>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the map below to answer this question.  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> Which of the following pairs of settlements is intervisible? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Abuojo and Hua </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Miki and Abuojo </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hua and Bikun </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bikun and Abuojo </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Impervisible translated to having a predominantly rocky terrain not allowing for water to pass through.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2003>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the map below to answer this question.  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The approximate gradient between the point marked X and the trigonometric station is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1:7 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">1:9 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">1:11 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">1:13 </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Gradient</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">change in horizontal distance<hr size=\"1\" />change in vertical data</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">change in measured distance with ruler<hr size=\"1\" />change in measured height using contours</td></tr></table></div>  <br/>  Scale = 1cm : 1km or 1 : 100,000  <br/>  = 1/13</div>", "topic": "PRATICAL GEOGRAPHY I : ELEMENTARY SURVEYING CHAIN AND PRISMATIC"}, {"id": "objective>Geography>2003>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the map below to answer this question.  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The most important economic activity in Nuriki District is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fishing </div>", "<div style=\"font-family:Cambria;font-size:17px;\">farming </div>", "<div style=\"font-family:Cambria;font-size:17px;\">mining </div>", "<div style=\"font-family:Cambria;font-size:17px;\">lumbering </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Farmland are scattered all around the map. The velocity of rivers will prove risk for fishing.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2003>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the map below to answer this question.  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The total land area of Nuriki District is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">290sq km </div>", "<div style=\"font-family:Cambria;font-size:17px;\">300sq km </div>", "<div style=\"font-family:Cambria;font-size:17px;\">310sq km </div>", "<div style=\"font-family:Cambria;font-size:17px;\">320sq km </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Area = length × Breadth  <br/>  = 6cm × 5cm  <br/>  = 6km × 5km = 30sqkm.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2003>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the map below to answer this question.  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The steepest part of the area is devoid of settlement because it </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">lacks roads </div>", "<div style=\"font-family:Cambria;font-size:17px;\">is too high </div>", "<div style=\"font-family:Cambria;font-size:17px;\">is thinly vegetated </div>", "<div style=\"font-family:Cambria;font-size:17px;\">is prone to erosion </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The steepest part of the area of devoid settlement because it is prone to erosion as a result of the slope.</div>", "topic": "PRATICAL GEOGRAPHY I : MAP READING AND INTERPRETATION"}, {"id": "objective>Geography>2003>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer this question. <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> If the management of school Y decided to award scholarship to the top 10% of the students, determine the lowest mark to qualify for scholarship. </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">86% </div>", "<div style=\"font-family:Cambria;font-size:17px;\">82% </div>", "<div style=\"font-family:Cambria;font-size:17px;\">78% </div>", "<div style=\"font-family:Cambria;font-size:17px;\">74% </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Trace the graph to Cumulative frequency of 90 & trace that part down to examination mark on x-axis.</div>", "topic": "PRATICAL GEOGRAPHY I : INTERPRETATION OF STATISTICAL DATA; MAPS AND DIAGRAMS"}, {"id": "objective>Geography>2003>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer this question. <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> How many students scored between 6% and 60%? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">70 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">66 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">62 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">58 </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Trace from x-axis 60% exam score up to the curve & trace this to the y-axis to get the difference = 70.</div>", "topic": "PRATICAL GEOGRAPHY I : INTERPRETATION OF STATISTICAL DATA; MAPS AND DIAGRAMS"}, {"id": "objective>Geography>2003>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The first stage in a compass survey is to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mark each traverse station with a peg </div>", "<div style=\"font-family:Cambria;font-size:17px;\">determine the magnetic inclination of the area </div>", "<div style=\"font-family:Cambria;font-size:17px;\">take a walk around the field and make notes  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">determine the preparedness of the team </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Marking each traverse station with a peg is the 1st stage in a a compass survey after which compass bearings can there be determined from origin.</div>", "topic": "PRATICAL GEOGRAPHY I : ELEMENTARY SURVEYING CHAIN AND PRISMATIC"}, {"id": "objective>Geography>2003>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the distance between two places on a map is 2cm while the distance on land is 4km, the scale of the map is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1:50000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1:100000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1:500000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1:200000</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Scale = Map length : Ground length  <br/>  1km = 100,000cm  <br/>  If 2cm : 4km  <br/>  ≈ 1 : 200,000  <br/> ∴ 2cm : 400,000cm</div>", "topic": "PRATICAL GEOGRAPHY I : SCALE AND MEASUREMENT DISTANCES"}, {"id": "objective>Geography>2003>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The existence of the Namibia Desert can be partly attributed to  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">coastal deforestation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the cold benguela Current </div>", "<div style=\"font-family:Cambria;font-size:17px;\">persistent offshore winds </div>", "<div style=\"font-family:Cambria;font-size:17px;\">exessive fishing </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Namib Desert's existence can be partly attributed to the cold Benguela Current. The Benguela Current is a cold, northward flowing ocean current that forms part of the South Atlantic Ocean's broader circulation. It brings cold, low-salinity water from the Southern Ocean to the west coast of Southern Africa. This results in the arid conditions that characterize the Namib Desert.</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL HAZARDS"}, {"id": "objective>Geography>2003>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If an event that starts at 11.00 am at station X appears on the screen at 5.00 am (same day) at station Z, the longitudinal difference between the two station is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">75<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">90<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">120<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">165<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span> </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">1hr = 15°  <br/>  If time difference = 11am - 5am  <br/>  ∴ Longitudinal difference = 6 × 15° = 90° </div>", "topic": "PRATICAL GEOGRAPHY I : MAP READING AND INTERPRETATION"}, {"id": "objective>Geography>2003>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The two most important determinants of air temperature of a region are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">evaporation and sunshine hours </div>", "<div style=\"font-family:Cambria;font-size:17px;\">wind and air mass </div>", "<div style=\"font-family:Cambria;font-size:17px;\">latitude and altitude </div>", "<div style=\"font-family:Cambria;font-size:17px;\">rainfall and humidity </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Latitude & altitude are the most important determinants of air temperature of a region. The closer the latitude to Equator, the hotter the air masses & vice versa. Higher altitudes are associated with cooler air masses as air is forced to rise & condense.</div>", "topic": "PRATICAL GEOGRAPHY II : WEATHER AND CLIMATE"}, {"id": "objective>Geography>2003>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Quarz, feldspar and mica are three principals that can easily be seen in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">basalt </div>", "<div style=\"font-family:Cambria;font-size:17px;\">coal </div>", "<div style=\"font-family:Cambria;font-size:17px;\">granite </div>", "<div style=\"font-family:Cambria;font-size:17px;\">limestone </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Quartz feldspar & mica make up granitic rocks. They are crystalline in structure and hard with characteristic difference in colour.</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2003>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The two areas of the world where cool ocean currents have contributed to the development of deserts along the coastal fringes are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Namibia and Bangladesh </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Somalia and Western Australia </div>", "<div style=\"font-family:Cambria;font-size:17px;\">California and Ghana </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Morocco and Peru </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Somalia & Western Australia have desert landscapes encouraged by local cold coastal currents running parallel to their coasts.</div>", "topic": "REGIONAL GEOGRAPHY : AFRICA ON BROAD OUTLINE"}, {"id": "objective>Geography>2003>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The duration of sunshine is measured by the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">aneroid barometer </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Campbell-strokes recorder </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cup-anemometer </div>", "<div style=\"font-family:Cambria;font-size:17px;\">minimum-maximum thermometers </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Campbell - stocks recorder measures duration of Sunshine. Barometer measures air pressure, anemometer wind speed.</div>", "topic": "PRATICAL GEOGRAPHY II : WEATHER AND CLIMATE"}, {"id": "objective>Geography>2003>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The rock with the least carbon is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">coal </div>", "<div style=\"font-family:Cambria;font-size:17px;\">sandstone </div>", "<div style=\"font-family:Cambria;font-size:17px;\">marble </div>", "<div style=\"font-family:Cambria;font-size:17px;\">lignite </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The rock with the least carbon is sandstone. Sandstone is a type of rock that is made up of sand-sized minerals or rock grains. Most sandstone is composed of quartz and/or feldspar because these are the most common minerals in the Earth's crust. It contains very little to no carbon, unlike coal and lignite which are carbon-rich.</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2003>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a karst topography, the visible features on the landscape include</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sinkhole </div>", "<div style=\"font-family:Cambria;font-size:17px;\">tunnel </div>", "<div style=\"font-family:Cambria;font-size:17px;\">stalactite </div>", "<div style=\"font-family:Cambria;font-size:17px;\">stalagmite </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The sinkhole is one of the profound features in a Karst topography/limestone region as water dissolves joints at areas of least resistance to form spectacular depressions.</div>", "topic": "PRATICAL GEOGRAPHY II : LANDFORMS"}, {"id": "objective>Geography>2003>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A landform that may result mainly from wind erosion is a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">barchan </div>", "<div style=\"font-family:Cambria;font-size:17px;\">self dune </div>", "<div style=\"font-family:Cambria;font-size:17px;\">wadi </div>", "<div style=\"font-family:Cambria;font-size:17px;\">deflation hollow </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Deflation hollow are cavities created by wind in the desert wadiis are formed by flash floods while barchan and seif dunes are made y wind deposition.</div>", "topic": "PRATICAL GEOGRAPHY II : LANDFORMS"}, {"id": "objective>Geography>2003>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In humid tropical regions, the major soil type is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">podzol </div>", "<div style=\"font-family:Cambria;font-size:17px;\">chernozem </div>", "<div style=\"font-family:Cambria;font-size:17px;\">latosol </div>", "<div style=\"font-family:Cambria;font-size:17px;\">lithsol </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Latosols are common in humid tropical regions rich in laterite (red soil) & covered by tropical vegetation.</div>", "topic": "PRATICAL GEOGRAPHY II : SOILS"}, {"id": "objective>Geography>2003>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Bush burning affects the atmosphere directly by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">killing soil microbes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">adding to carbon (IV) oxide accumulation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">leaving the land surface bare </div>", "<div style=\"font-family:Cambria;font-size:17px;\">adding ashes to the soil  </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Bush burning affects the gaseous part of the biosphere (the atmosphere) by adding CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> accumulation.</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL HAZARDS"}, {"id": "objective>Geography>2003>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A process whereby a plant community is replaced by another is known as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">colonization </div>", "<div style=\"font-family:Cambria;font-size:17px;\">succession </div>", "<div style=\"font-family:Cambria;font-size:17px;\">competition </div>", "<div style=\"font-family:Cambria;font-size:17px;\">consolidation </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Succession in ecology is a process whereby a plant community is replaced by another e.g mosses replaced by ferns.</div>", "topic": "PRATICAL GEOGRAPHY II : VEGETATION"}, {"id": "objective>Geography>2003>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most visible form of soil erosion is  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">wind erosion </div>", "<div style=\"font-family:Cambria;font-size:17px;\">splash erosion </div>", "<div style=\"font-family:Cambria;font-size:17px;\">sheet erosion </div>", "<div style=\"font-family:Cambria;font-size:17px;\">gully erosion </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Gully erosion is the most visible form of soil erosion. It occurs when runoff water accumulates and rapidly flows in narrow channels during or immediately after heavy rains or melting snow, removing the soil to a considerable depth. Gullies are typically deeper than 30cm. This makes it the most visible form of soil erosion.</div>", "topic": "PRATICAL GEOGRAPHY II : SOILS"}, {"id": "objective>Geography>2003>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Softwood from coniferous forest is mainly used as raw material for the production of  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pulp and paper </div>", "<div style=\"font-family:Cambria;font-size:17px;\">animal feed and fibre </div>", "<div style=\"font-family:Cambria;font-size:17px;\">non-alcoholic beverages </div>", "<div style=\"font-family:Cambria;font-size:17px;\">poles and planks </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Softwood from coniforest forests found in the coller regions close to the poles. North and south are best suited for the pulp and paper industry.</div>", "topic": "PRATICAL GEOGRAPHY II : VEGETATION"}, {"id": "objective>Geography>2003>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In soil profile, the C-horizon can be described as the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">topmost layer that may include organic litter </div>", "<div style=\"font-family:Cambria;font-size:17px;\">zone relatively unaffected by soil-forming process</div>", "<div style=\"font-family:Cambria;font-size:17px;\">portion of the soil affected by leaching  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">zone of accumulation rich in bases and organic matter </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The a-layer is rich in organic litter  <br/>  b - layer has decomposition and leaching occurring while C- layer is relatively unaffected by soil forming processes.</div>", "topic": "PRATICAL GEOGRAPHY II : SOILS"}, {"id": "objective>Geography>2003>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the consequences of the polar icecaps melting is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">submergence of existing coast lands </div>", "<div style=\"font-family:Cambria;font-size:17px;\">emergence of submerged islands </div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase in global mean temperature </div>", "<div style=\"font-family:Cambria;font-size:17px;\">drier conditions in the tropical areas </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Polar ice caps melting is a result of global warming/climate change with/which is an increase in global mean temperature.</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL HAZARDS"}, {"id": "objective>Geography>2003>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The factor that best explains the large concentration of population in Java is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fertile soils </div>", "<div style=\"font-family:Cambria;font-size:17px;\">large mineral deposits  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">nearness to the sea </div>", "<div style=\"font-family:Cambria;font-size:17px;\">industrial agglomeration </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The fertile/nutrient rich volcanic soil encouraged agric and hence population density in Jowak land of Indonesia.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2003>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most important characteristics of a population that enhance rapid economic development is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">total size </div>", "<div style=\"font-family:Cambria;font-size:17px;\">level of education </div>", "<div style=\"font-family:Cambria;font-size:17px;\">age-structure </div>", "<div style=\"font-family:Cambria;font-size:17px;\">sex ratio </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The level of education influences to a large extent the rapid economic development of a population. As it is involved in several metrics key of such is Human Development Index.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2003>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The pattern of rural population distribution in a region is determined mainly by the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">quality of the land </div>", "<div style=\"font-family:Cambria;font-size:17px;\">size of the land </div>", "<div style=\"font-family:Cambria;font-size:17px;\">quality of the population </div>", "<div style=\"font-family:Cambria;font-size:17px;\">size of the population </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Rural population are (HDI) majorly agarian. Hence, quality of land for agric influences the pattern of rural population distribution.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2003>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The crossing of a boundary between two countries by a migrant is best described as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">emigration </div>", "<div style=\"font-family:Cambria;font-size:17px;\">immigration </div>", "<div style=\"font-family:Cambria;font-size:17px;\">out-migration </div>", "<div style=\"font-family:Cambria;font-size:17px;\">international migration </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">International migration entails population crossing a cross at least one international boundary between sovereign nations.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2003>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Urban growth in sub-Saharan Africa has been enhanced mostly by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">natural population growth </div>", "<div style=\"font-family:Cambria;font-size:17px;\">rural-urban migration </div>", "<div style=\"font-family:Cambria;font-size:17px;\">agricultural development </div>", "<div style=\"font-family:Cambria;font-size:17px;\">housing development </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Rural- Urban migration has been key in the rapid urban growth experienced in Sub-Saharan African cities.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2003>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One major characteristic of rural settlements is that they </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">are heterogeneous </div>", "<div style=\"font-family:Cambria;font-size:17px;\">are homogeneous </div>", "<div style=\"font-family:Cambria;font-size:17px;\">are large in size </div>", "<div style=\"font-family:Cambria;font-size:17px;\">have many functions </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Rural settlements are usually made up of people from similar ancestral and cultural lineage/heritage, hence being homogenous. </div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2003>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Industrial Europe, North America and Japan are the major importer of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">raw materials </div>", "<div style=\"font-family:Cambria;font-size:17px;\">manufactured goods </div>", "<div style=\"font-family:Cambria;font-size:17px;\">iron and steel </div>", "<div style=\"font-family:Cambria;font-size:17px;\">building materials </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Iron & steel are major inputs for production by the developed countries of Europe, North America and Japan to produce industrial and home appliances and machines such as cars, ships etc</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2003>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Manufacturing industries contribute to national development by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">adding value to local products </div>", "<div style=\"font-family:Cambria;font-size:17px;\">attracting foreign migrants </div>", "<div style=\"font-family:Cambria;font-size:17px;\">producing a variety of goods </div>", "<div style=\"font-family:Cambria;font-size:17px;\">building industrial estates </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> When local raw materials are processed by manufacturing industries, the market prices of these products increase. Thus adding value to local products and contributing to national development via better GDP.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2003>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Opencast mining often leads to the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">degradation of the topsoil </div>", "<div style=\"font-family:Cambria;font-size:17px;\">replenishment of the soil </div>", "<div style=\"font-family:Cambria;font-size:17px;\">production of fertile soils  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">extinction of animals </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Open Cast mining involves controlled/ uncontrolled blasting of the earth surface to extract mineral resources leading to degradation of the top soil.</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL HAZARDS"}, {"id": "objective>Geography>2003>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The reindeer and the camel are commonly used as beast of burden in the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Rockies and the Atacama Desert </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Polar region and the Sahara Desert </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Antarctical and the Australian Desert </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Andes and the Kalahari Desert </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Reindeers are beasts of burden adapted to ice conditions while camels are adapted to dusty desert conditions thus pro-polar and sahara desert respectively.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2003>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following groups of factors is most likely to influence industrial location? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Raw material, energy and market </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Capital, raw material and population growth </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Market, emigration and labour </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Transport, raw material and migration </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Of all options provided the raw material, energy and market combination will most likely influence industrial location choice. Raw materials and energy are input factors while inlet output factor for ready purchase of product.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2003>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Secondary economic activities are those that involve the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">packaging of finished goods </div>", "<div style=\"font-family:Cambria;font-size:17px;\">distribution of raw materials </div>", "<div style=\"font-family:Cambria;font-size:17px;\">distribution of finished goods </div>", "<div style=\"font-family:Cambria;font-size:17px;\">processing of raw materials </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Primary economic activities are  <br/> agro-based → Fishing, crop cultivation, animal rearing.  <br/>  secondary → Production/processing of raw materials.  <br/>  Tertiary →  logistics, marketing.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2003>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The towns that owe their origin and growth to the presence of localized mineral resources are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Jos and Abeokuta </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Kano and Enugu </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Jos and Enugu </div>", "<div style=\"font-family:Cambria;font-size:17px;\">port Harcourt and Onitsha </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Towns that owe their origin and growth to the presence of localized mineral resources are often located near mines or other extraction sites. In Nigeria, Jos and Enugu are examples of such towns. Jos is known for its tin mining activities while Enugu is known for coal mining. Therefore, the correct answer is 'Jos and Enugu'.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2003>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Soil conservation can be achieved through </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">floriculture </div>", "<div style=\"font-family:Cambria;font-size:17px;\">monoculture </div>", "<div style=\"font-family:Cambria;font-size:17px;\">mechanization </div>", "<div style=\"font-family:Cambria;font-size:17px;\">strip-cropping </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Strip-cropping is crop cultivation is lines or steps which help in conserving soils especially along slopes & highland areas.</div>", "topic": "PRATICAL GEOGRAPHY II : SOILS"}, {"id": "objective>Geography>2003>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the steel-rolling mills in Nigeria is located at  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Ajaokuta </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ovwian-Aladja </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Jos </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Enugu </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The steel-rolling mill referred to in the question is located at Ovwian-Aladja in Delta State, Nigeria. This is a part of the Delta Steel Company, a subsidiary of the Nigerian Steel Development Authority.</div>", "topic": "REGIONAL GEOGRAPHY : BROAD OUTLINE OF NIGERIA"}, {"id": "objective>Geography>2003>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Wheat has gained importance in Nigeria's agriculture as a result of the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increased use of fertilizers </div>", "<div style=\"font-family:Cambria;font-size:17px;\">gradual change in climate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">increased purchasing power of the citizen </div>", "<div style=\"font-family:Cambria;font-size:17px;\">introduction of large-scale irrigation </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The importance of wheat in Nigeria's agriculture has increased due to the introduction of large-scale irrigation. Irrigation has allowed for the cultivation of wheat in areas where it was previously not possible due to lack of sufficient rainfall. This has increased the production of wheat in the country.</div>", "topic": "REGIONAL GEOGRAPHY : PLANTATION AGRICULTURE IN WEST AND EAST AFRICA"}, {"id": "objective>Geography>2003>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Annual total rainfall decreases generally from the south to the north of Nigeria because of the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">longitudinal spread along the coast </div>", "<div style=\"font-family:Cambria;font-size:17px;\">latitudinal spread from the sea </div>", "<div style=\"font-family:Cambria;font-size:17px;\">relief pattern of the country </div>", "<div style=\"font-family:Cambria;font-size:17px;\">drainage pattern of the country </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Coastal air masses play a huge role in influencing annual total rainfall across the Nigerian landscape as one moves hinterland.</div>", "topic": "REGIONAL GEOGRAPHY : GEOGRAPHICAL REGIONS OF NIGERIA"}, {"id": "objective>Geography>2003>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Lagos area has emerged as the most prominent destination for internal migration because it is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">on a high plain and highly industrialized </div>", "<div style=\"font-family:Cambria;font-size:17px;\">close to the coast and densely populated </div>", "<div style=\"font-family:Cambria;font-size:17px;\">highly industrialized and highly urbanized </div>", "<div style=\"font-family:Cambria;font-size:17px;\">agriculturally productive and close to the coast </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Lagos is the most urbanized & industrialized city in Nigeria thus serving as a combination of pull factors for internal migration.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2003>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The planting of eucalyptus trees on the Jos Plateau is to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">reclaim the soil </div>", "<div style=\"font-family:Cambria;font-size:17px;\">provide firewood </div>", "<div style=\"font-family:Cambria;font-size:17px;\">prevent desertification </div>", "<div style=\"font-family:Cambria;font-size:17px;\">provide wind breakers  </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Eucalyptus trees apart from serving as wind breakers majorly is used as a tool to prevent desertification through afforestation.</div>", "topic": "PRATICAL GEOGRAPHY II : VEGETATION"}, {"id": "objective>Geography>2003>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Industrialization in Nigeria can best be promoted through the development of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">textile manufacturing </div>", "<div style=\"font-family:Cambria;font-size:17px;\">vegetable oil processing </div>", "<div style=\"font-family:Cambria;font-size:17px;\">iron and steel processing </div>", "<div style=\"font-family:Cambria;font-size:17px;\">automobile manufacturing </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Modern day pre-21st century industrialization was birthed on the wings of iron and steel processing industries. The likes oof USSR/Russia, USA & Germany, led aircraft, ships and automobile productions with iron and steel as raw materials. </div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2003>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer this question.  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The most common mature soil types in the shaded portion are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">alluvial soil </div>", "<div style=\"font-family:Cambria;font-size:17px;\">forest soils </div>", "<div style=\"font-family:Cambria;font-size:17px;\">drift soils </div>", "<div style=\"font-family:Cambria;font-size:17px;\">laterite soils </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Laterite soil is dominant in Western, Eastern & Central Africa where equatorial forests are found. Of note is the Congo basin similar to the Amazons.</div>", "topic": "PRATICAL GEOGRAPHY II : SOILS"}, {"id": "objective>Geography>2003>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer this question.  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The condition that promotes the formation of these soils is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">distinct wet and dry seasons </div>", "<div style=\"font-family:Cambria;font-size:17px;\">dense tropical rain forest </div>", "<div style=\"font-family:Cambria;font-size:17px;\">extensive savanna grassland </div>", "<div style=\"font-family:Cambria;font-size:17px;\">dense rural population </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Being around the Equator encourages longer period of sunshine and high rainfall supporting evergreen forests.</div>", "topic": "PRATICAL GEOGRAPHY II : SOILS"}, {"id": "objective>Geography>2003>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The single most successful large-scale irrigation project in tropical Africa is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">volta River Project </div>", "<div style=\"font-family:Cambria;font-size:17px;\">chad Basin project </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gezira Scheme </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nile Delta Scheme </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Nile-Delta Scheme of Egypt is one of the most heavily inverted and successful large-scale irrigation project with series of dams & canals.</div>", "topic": "REGIONAL GEOGRAPHY : IRRIGATION AGRICULTURE IN THE NILE AND NIGER BASIN"}, {"id": "objective>Geography>2003>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Iron Ore mining in Africa is carried out in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Ghana, Niger and Egypt </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Democratic Republic of Congo, Namibia and Sierra Leone </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tunisha, Democratic Republic of Congo and Ghana </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Kenya, Tunisha and Sudan </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">DR Congo, Namibia and Sierra Leone are heavy weights in the Iron-ore mining industry with huge reserves of this mineral resource with their territories. </div>", "topic": "REGIONAL GEOGRAPHY : MINERAL EXPLOITATION"}, {"id": "objective>Geography>2003>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Two good examples of sheltered estuaries which are also natural harbours in West Africa are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Lagos and Takoradi </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Banjul and Warri </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Freetown and Dakar </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Warri  and Accra </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Freetown in Sierra Leone & Dakar Senegal are both sheltered Estuaries as well a natural harbours in West Africa. Freetown is one of the most spectacular sheltered harbours in the world. </div>", "topic": "REGIONAL GEOGRAPHY : WATER BODIES"}];
